1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const INSURANCE_VALUES: Record<string, number> = {
14	  sword: 1000,
15	  amulet: 600,
16	  staff: 800,
17	  potion: 400,
18	  rune: 250,
19	  moonstone: 250,
20	};
21	
22	const DEDUCTIBLE = 100;
23	const CAP_MULTIPLIER = 2;
24	
25	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
26	
27	const enchantmentOf = (item: Item): number => item.enchantment ?? 0;
28	
29	const CURSE_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const LOYALTY_DISCOUNT_RATE = 0.2;
33	const LOYALTY_YEARS_THRESHOLD = 2;
34	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
35	
36	type Damage = { itemType: string; amount: number };
37	type Incident = { cause: string; damages: Damage[] };
38	type QuoteStep = { op: "quote"; items: Item[] };
39	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
40	type Step = QuoteStep | ClaimStep;
41	
42	type Scenario = {
43	  customer: { yearsWithMHPCO: number };
44	  steps: Step[];
45	};
46	
47	type QuoteResult = { premium: number };
48	type ClaimResult = { payout: number; remainingCap: number };
49	type StepResult = QuoteResult | ClaimResult;
50	
51	const COMPONENT_BLOCK_SIZE = 3;
52	const COMPONENT_BLOCK_PREMIUM = 60;
53	
54	const isComponentBlock = (group: Item[]): boolean => group.length === COMPONENT_BLOCK_SIZE;
55	
56	const sumOfBasePremiums = (items: Item[]): number =>
57	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
58	
59	const groupByType = (items: Item[]): Item[][] =>
60	  Object.values(Object.groupBy(items, (item) => item.type));
61	
62	const basePremiumForGroup = (group: Item[]): number =>
63	  isComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(group);
64	
65	const basePremiumFor = (items: Item[]): number =>
66	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
67	
68	type SurchargeRule = { rate: number; applies: (item: Item) => boolean };
69	
70	const SURCHARGE_RULES: SurchargeRule[] = [
71	  { rate: CURSE_SURCHARGE_RATE, applies: (item) => !!item.cursed },
72	  {
73	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
74	    applies: (item) => enchantmentOf(item) >= HIGH_ENCHANTMENT_THRESHOLD,
75	  },
76	];
77	
78	const surchargeForRule = (items: Item[], rule: SurchargeRule): number =>
79	  items.reduce(
80	    (sum, item) => (rule.applies(item) ? sum + BASE_PREMIUMS[item.type] * rule.rate : sum),
81	    0,
82	  );
83	
84	const surchargesFor = (items: Item[]): number =>
85	  SURCHARGE_RULES.reduce((total, rule) => total + surchargeForRule(items, rule), 0);
86	
87	type Customer = { yearsWithMHPCO: number };
88	type PolicyContext = { customer: Customer; isFollowUp: boolean };
89	
90	type PolicyDiscountRule = { rate: number; applies: (context: PolicyContext) => boolean };
91	
92	const POLICY_DISCOUNT_RULES: PolicyDiscountRule[] = [
93	  {
94	    rate: LOYALTY_DISCOUNT_RATE,
95	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
96	  },
97	  {
98	    rate: FOLLOW_UP_DISCOUNT_RATE,
99	    applies: ({ isFollowUp }) => isFollowUp,
100	  },
101	];
102	
103	const policyDiscountsFor = (base: number, context: PolicyContext): number =>
104	  POLICY_DISCOUNT_RULES.reduce(
105	    (total, rule) => (rule.applies(context) ? total + base * rule.rate : total),
106	    0,
107	  );
108	
109	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
110	  const base = basePremiumFor(items);
111	  const surcharges = surchargesFor(items);
112	  const discounts = policyDiscountsFor(base, { customer, isFollowUp });
113	  return {
114	    premium: Math.ceil(base + surcharges - discounts + base * FIRST_INSURANCE_RATE + PROCESSING_FEE),
115	  };
116	};
117	
118	const isFollowUpStep = (index: number): boolean => index > 0;
119	
120	type Policy = { items: Item[]; remainingCap: number };
121	
122	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
123	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
124	
125	const insuranceSumFor = (items: Item[]): number =>
126	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
127	
128	const createPolicy = (items: Item[]): Policy => ({
129	  items,
130	  remainingCap: CAP_MULTIPLIER * insuranceSumFor(items),
131	});
132	
133	const reimbursementFor = (item: Item, amount: number): number =>
134	  enchantmentOf(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
135	    ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE
136	    : amount;
137	
138	const payoutForDamage = (damage: Damage, policy: Policy): number => {
139	  const item = policy.items.find((it) => it.type === damage.itemType);
140	  const reimbursement = item ? reimbursementFor(item, damage.amount) : damage.amount;
141	  return Math.max(0, reimbursement - DEDUCTIBLE);
142	};
143	
144	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
145	  const payout = incident.damages.reduce(
146	    (sum, damage) => sum + payoutForDamage(damage, policy),
147	    0,
148	  );
149	  policy.remainingCap -= payout;
150	  return { payout, remainingCap: policy.remainingCap };
151	};
152	
153	const handleQuoteStep = (
154	  step: QuoteStep,
155	  index: number,
156	  customer: Customer,
157	  policies: Policy[],
158	): QuoteResult => {
159	  policies[index] = createPolicy(step.items);
160	  return quotePremium(step.items, customer, isFollowUpStep(index));
161	};
162	
163	const handleClaimStep = (step: ClaimStep, policies: Policy[]): ClaimResult =>
164	  processClaim(policies[step.policy], step.incident);
165	
166	const handleStep = (
167	  step: Step,
168	  index: number,
169	  customer: Customer,
170	  policies: Policy[],
171	): StepResult =>
172	  step.op === "quote"
173	    ? handleQuoteStep(step, index, customer, policies)
174	    : handleClaimStep(step, policies);
175	
176	export const processScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
177	  const policies: Policy[] = [];
178	  const results = steps.map((step, index) => handleStep(step, index, customer, policies));
179	  return { results };
180	};
